    while (t--) {
        int n, m;
        cin >> n >> m;

        vector<int> completed_jobs(m);
        for (int i = 0; i < m; i++) {
            cin >> completed_jobs[i];
        }
        vector<int> remaining_jobs(n + 1, 1);
        for (int job : completed_jobs) {
            remaining_jobs[job] = 0;
        }

        // Collect the remaining jobs
        vector<int> unfinished_jobs;
        for (int i = 1; i <= n; i++) {
            if (remaining_jobs[i] == 1) {
                unfinished_jobs.push_back(i);
            }
        }

        // Assign jobs to Chef and Assistant
        vector<int> chef_jobs;
        vector<int> assistant_jobs;

        for (int i = 0; i < unfinished_jobs.size(); i++) {
            if (i % 2 == 0) {
                chef_jobs.push_back(unfinished_jobs[i]); // Chef takes the job
            } else {
                assistant_jobs.push_back(unfinished_jobs[i]); // Assistant takes the job
            }
        }
        if (!chef_jobs.empty()) {
            for (int job : chef_jobs) {
                cout << job << " ";
            }
            cout << endl;
        } else {
            cout << "-1" << endl; // If Chef has no jobs
        }

