int main() {
    int t; 
    scanf("%d", &t);

    while (t--) {
        int n, m; 
        scanf("%d %d", &n, &m);

        int *completed_jobs = (int *)malloc(m * sizeof(int));
        for (int i = 0; i < m; i++) {
            scanf("%d", &completed_jobs[i]);
        }

        int *remaining_jobs = (int *)calloc(n + 1, sizeof(int));
        for (int i = 1; i <= n; i++) {
            remaining_jobs[i] = 1; 
        }

        for (int i = 0; i < m; i++) {
            remaining_jobs[completed_jobs[i]] = 0; 
        }

        int *unfinished_jobs = (int *)malloc(n * sizeof(int));
        int unfinished_count = 0;
        for (int i = 1; i <= n; i++) {
            if (remaining_jobs[i] == 1) {
                unfinished_jobs[unfinished_count++] = i; 
            }
        }

        // Chef's jobs
        if (unfinished_count > 0) {
            for (int i = 0; i < unfinished_count; i += 2) {
                printf("%d ", unfinished_jobs[i]); 
            }
            printf("\n"); 
        } else {
            printf("-1\n"); 
        }

        // Assistant's jobs
        if (unfinished_count > 1) {
            for (int i = 1; i < unfinished_count; i += 2) {
                printf("%d ", unfinished_jobs[i]); 
            }
            printf("\n"); 
        } else {
            printf("-1\n"); 
        }

        free(completed_jobs);
        free(remaining_jobs);
        free(unfinished_jobs);
    }

    return 0;
}

