const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

function jobAssignment(t, testCases) {
    let results = [];

    for (let i = 0; i < t; i++) {
        const [n, m] = testCases[i][0]; // Total jobs and completed jobs
        const completedJobs = testCases[i][1]; // Completed jobs

        // Create an array to mark completed jobs
        const remainingJobs = new Array(n + 1).fill(true); // All jobs initially marked as unfinished

        // Mark completed jobs
        for (let job of completedJobs) {
            remainingJobs[job] = false;
        }

        // Collect the remaining jobs
        const unfinishedJobs = [];
        for (let j = 1; j <= n; j++) {
            if (remainingJobs[j]) {
                unfinishedJobs.push(j);
            }
        }

        // Assign jobs to Chef and Assistant
        const chefJobs = [];
        const assistantJobs = [];

        for (let j = 0; j < unfinishedJobs.length; j++) {
            if (j % 2 === 0) {
                chefJobs.push(unfinishedJobs[j]); // Chef takes the job
            } else {
                assistantJobs.push(unfinishedJobs[j]); // Assistant takes the job
            }
        }

        // Collect results for Chef
        if (chefJobs.length > 0) {
            results.push(chefJobs.join(" ")); // Print Chef's jobs
        } else {
            results.push("-1"); // If Chef has no jobs
        }

        // Collect results for Assistant
        if (assistantJobs.length > 0) {
            results.push(assistantJobs.join(" ")); // Print Assistant's jobs
        } else {
            results.push("-1"); // If Assistant has no jobs
        }
    }

    // Output results
    console.log(results.join("\n"));
}

// Read input from the user
const input = [];
rl.on('line', (line) => {
    input.push(line);
}).on('close', () => {
    const t = parseInt(input[0]);
    const testCases = [];

    for (let i = 1; i < input.length; i += 2) {
        const [n, m] = input[i].split(' ').map(Number);
        const completedJobs = input[i + 1].split(' ').map(Number);
        testCases.push([[n, m], completedJobs]);
    }

    jobAssignment(t, testCases);
});
